import { useEffect, useMemo, useState } from "react";
import API, { getApiError } from "../services/api";
import { subscribeToRealtime } from "../services/realtime";
import { formatDisplayDate } from "../utils/membership";

const ALL_MONTHS = "__all__";

const currencyFormatter = new Intl.NumberFormat("en-IN", {
  style: "currency",
  currency: "INR",
  maximumFractionDigits: 0
});

function getMonthKey(value) {
  if (!value) {
    return "";
  }

  return value.slice(0, 7);
}

function formatMonthLabel(monthKey) {
  if (!monthKey) {
    return "Unknown";
  }

  return new Intl.DateTimeFormat("en-US", {
    month: "long",
    year: "numeric"
  }).format(new Date(`${monthKey}-01T00:00:00`));
}

function formatCurrency(value) {
  return currencyFormatter.format(value || 0);
}

function getPaymentDate(payment) {
  return payment.recordedOn || payment.planStart || "";
}

function getPaymentEntries(customers) {
  return customers.flatMap((customer) => {
    const history =
      Array.isArray(customer.membershipHistory) && customer.membershipHistory.length
        ? customer.membershipHistory
        : [
            {
              plan: customer.plan,
              amountPaid: customer.amountPaid,
              planStart: customer.planStart,
              planEnd: customer.planEnd,
              recordedOn: customer.planStart
            }
          ];

    return history.map((entry, index) => ({
      entryId: `${customer.customerId}-${getPaymentDate(entry) || "payment"}-${index}`,
      customerId: customer.customerId,
      fullName: customer.fullName,
      phone: customer.phone,
      plan: entry.plan,
      amountPaid: entry.amountPaid,
      planStart: entry.planStart,
      planEnd: entry.planEnd,
      recordedOn: getPaymentDate(entry)
    }));
  });
}

export default function Payments() {
  const [customers, setCustomers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [selectedMonth, setSelectedMonth] = useState("");

  const loadCustomers = async () => {
    setLoading(true);
    setError("");

    try {
      const response = await API.get("/customers");
      setCustomers(response.data);
    } catch (requestError) {
      setError(getApiError(requestError, "Unable to load payment details."));
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadCustomers();
    return subscribeToRealtime("gym:dataChanged", loadCustomers);
  }, []);

  const paymentEntries = useMemo(
    () =>
      getPaymentEntries(customers).sort((left, right) =>
        getPaymentDate(right).localeCompare(getPaymentDate(left))
      ),
    [customers]
  );

  const paymentMonths = useMemo(() => {
    const grouped = paymentEntries.reduce((months, payment) => {
      const monthKey = getMonthKey(getPaymentDate(payment));

      if (!monthKey) {
        return months;
      }

      if (!months[monthKey]) {
        months[monthKey] = {
          monthKey,
          label: formatMonthLabel(monthKey),
          totalAmount: 0,
          customerCount: 0,
          payments: []
        };
      }

      months[monthKey].totalAmount += Number(payment.amountPaid) || 0;
      months[monthKey].customerCount += 1;
      months[monthKey].payments.push(payment);

      return months;
    }, {});

    return Object.values(grouped).sort((left, right) =>
      right.monthKey.localeCompare(left.monthKey)
    );
  }, [paymentEntries]);

  useEffect(() => {
    if (!paymentMonths.length) {
      setSelectedMonth("");
      return;
    }

    if (
      !selectedMonth ||
      (selectedMonth !== ALL_MONTHS &&
        !paymentMonths.some((month) => month.monthKey === selectedMonth))
    ) {
      setSelectedMonth(ALL_MONTHS);
    }
  }, [paymentMonths, selectedMonth]);

  const selectedMonthData =
    paymentMonths.find((month) => month.monthKey === selectedMonth) || null;

  const allPayments = paymentEntries.filter((payment) => getPaymentDate(payment));

  const selectedPayments =
    selectedMonth === ALL_MONTHS
      ? allPayments
      : selectedMonthData
        ? [...selectedMonthData.payments].sort((left, right) =>
            getPaymentDate(right).localeCompare(getPaymentDate(left))
          )
        : [];

  const selectedPaymentCount = selectedPayments.length;
  const selectedTotalAmount = selectedPayments.reduce(
    (sum, payment) => sum + (Number(payment.amountPaid) || 0),
    0
  );
  const averagePayment = selectedPaymentCount
    ? Math.round(selectedTotalAmount / selectedPaymentCount)
    : 0;

  const highestPayment = selectedPayments.reduce(
    (max, payment) => Math.max(max, Number(payment.amountPaid) || 0),
    0
  );

  const monthlyPeak = paymentMonths.reduce(
    (max, month) => Math.max(max, month.totalAmount),
    0
  );
  const selectedLabel =
    selectedMonth === ALL_MONTHS ? "All payments" : selectedMonthData?.label || "";
  const visibleMonths =
    selectedMonth === ALL_MONTHS
      ? paymentMonths
      : selectedMonthData
        ? [selectedMonthData]
        : [];

  return (
    <div className="page-stack">
      <section className="page-heading">
        <div>
          <h2>Payments</h2>
        </div>
      </section>

      {error ? <div className="status-banner status-banner--error">{error}</div> : null}

      <section className="summary-strip">
        <div>
          <strong>
            {loading
              ? "..."
              : selectedPaymentCount
                ? formatCurrency(selectedTotalAmount)
                : formatCurrency(0)}
          </strong>
          <span>
            {selectedMonth === ALL_MONTHS ? "Collected across all months" : "Collected in selected month"}
          </span>
        </div>
        <div>
          <strong>{loading ? "..." : selectedPaymentCount}</strong>
          <span>Payments recorded</span>
        </div>
        <div>
          <strong>{loading ? "..." : formatCurrency(averagePayment)}</strong>
          <span>Average payment</span>
        </div>
        <div>
          <strong>{loading ? "..." : formatCurrency(highestPayment)}</strong>
          <span>Highest single payment</span>
        </div>
      </section>

      <section className="panel-card">
        <div className="panel-card__header">
          <h3>Monthly collections</h3>
          {paymentMonths.length ? (
            <label className="field field--compact">
              <span>Select month</span>
              <select
                value={selectedMonth}
                onChange={(event) => setSelectedMonth(event.target.value)}
              >
                <option value={ALL_MONTHS}>All months</option>
                {paymentMonths.map((month) => (
                  <option key={month.monthKey} value={month.monthKey}>
                    {month.label}
                  </option>
                ))}
              </select>
            </label>
          ) : null}
        </div>

        {loading ? (
          <div className="panel-empty">Loading monthly collections...</div>
        ) : visibleMonths.length ? (
          <div className="payments-month-list">
            {visibleMonths.map((month) => {
              const ratio = monthlyPeak ? (month.totalAmount / monthlyPeak) * 100 : 0;

              return (
                <button
                  key={month.monthKey}
                  type="button"
                  className={`payment-month-card${
                    selectedMonth === month.monthKey ? " is-active" : ""
                  }`}
                  onClick={() => setSelectedMonth(month.monthKey)}
                >
                  <div className="payment-month-card__header">
                    <strong>{month.label}</strong>
                    <span>{month.customerCount} payments</span>
                  </div>
                  <div className="payment-month-card__bar">
                    <div style={{ width: `${Math.max(ratio, 8)}%` }} />
                  </div>
                  <p>{formatCurrency(month.totalAmount)}</p>
                </button>
              );
            })}
          </div>
        ) : (
          <div className="panel-empty">
            {selectedMonth === ALL_MONTHS
              ? "No payment data yet. Payments will appear here after customers are added."
              : "No collection data found for the selected month."}
          </div>
        )}
      </section>

      <section className="panel-card">
        <div className="panel-card__header">
          <h3>Payment entries</h3>
          {selectedLabel ? (
            <span className="badge badge--neutral">{selectedLabel}</span>
          ) : null}
        </div>

        {loading ? (
          <div className="panel-empty">Loading payment entries...</div>
        ) : selectedPayments.length ? (
          <div className="table-wrap">
            <table className="data-table">
              <thead>
                <tr>
                  <th>ID</th>
                  <th>Member</th>
                  <th>Plan</th>
                  <th>Paid on</th>
                  <th>Plan ends</th>
                  <th>Amount</th>
                </tr>
              </thead>
              <tbody>
                {selectedPayments.map((payment) => (
                  <tr key={payment.entryId}>
                    <td>#{payment.customerId}</td>
                    <td>
                      <div className="table-member">
                        <strong>{payment.fullName}</strong>
                        <span>{payment.phone}</span>
                      </div>
                    </td>
                    <td>{payment.plan}</td>
                    <td>{formatDisplayDate(payment.recordedOn)}</td>
                    <td>{formatDisplayDate(payment.planEnd)}</td>
                    <td>{formatCurrency(payment.amountPaid)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : (
          <div className="panel-empty">
            {selectedMonth === ALL_MONTHS
              ? "No payments recorded yet."
              : "No payments recorded for the selected month."}
          </div>
        )}
      </section>
    </div>
  );
}
